import{_ as i,c as t,d as l,o as d}from"./index-fe-DAs-K.js";const s={},e={class:"invite-rules-page"};function b(v,a){return d(),t("div",e,[...a[0]||(a[0]=[l('<h2 class="invite-rules-page-title" data-v-bb4d4055>活动规则详情</h2><section class="invite-rules-section" data-v-bb4d4055><h4 class="invite-rules-heading" data-v-bb4d4055>邀请返佣机制</h4><div class="invite-rules-callout" data-v-bb4d4055> 推荐新客下单即获得奖励，<b data-v-bb4d4055>一次邀请终身享受订单返佣红利</b>。 </div><ul class="invite-rules-list" data-v-bb4d4055><li data-v-bb4d4055>通过专属邀请链接或邀请码建立邀请关系，好友注册成功即生效。</li><li data-v-bb4d4055>累计邀请 3 人奖励 3 天专业版会员；累计邀请 5 人奖励 5 天专业版会员。</li><li data-v-bb4d4055>超过 5 人后，每多邀请 1 人额外奖励 2 天专业版会员，会员天数可累计叠加。</li><li data-v-bb4d4055>好友首次购买会员可获 10% 创作币返佣，续费返佣 5%，返佣以创作币形式即时到账。</li><li data-v-bb4d4055>被邀请的好友通过你的链接首次下单后，该笔订单视为你邀请的返佣订单。</li></ul></section><section class="invite-rules-section" data-v-bb4d4055><h4 class="invite-rules-heading" data-v-bb4d4055>提现规则</h4><ul class="invite-rules-list" data-v-bb4d4055><li data-v-bb4d4055>仅付费邀请用户可申请提现，且需至少邀请 3 位付费好友。</li><li data-v-bb4d4055>创作币余额满 100 即可提现，1 创作币 = 1 元人民币。</li><li data-v-bb4d4055>提现申请提交后约 1 个工作日审核，预计 7 个工作日内到账。</li><li data-v-bb4d4055>目前仅支持支付宝提现，请确保支付宝账号和真实姓名与本人一致。</li><li data-v-bb4d4055>因账号信息错误、账户异常等原因导致的提现失败，平台概不负责。</li></ul></section><section class="invite-rules-section" data-v-bb4d4055><h4 class="invite-rules-heading" data-v-bb4d4055>声明</h4><ul class="invite-rules-list" data-v-bb4d4055><li data-v-bb4d4055>根据业务发展和市场环境变化，活动规则可能调整，会通过官方渠道提前通知。</li><li data-v-bb4d4055>平台保留对违规刷量、虚假邀请、机器注册等行为的处理权。</li><li data-v-bb4d4055>本活动最终解释权归爱创作所有，如有疑问请联系客服。</li></ul></section>',4)])])}const c=i(s,[["render",b],["__scopeId","data-v-bb4d4055"]]);export{c as default};
